+fn path_matches(cookie_path: &str, request_path: &str) -> bool {
+    if cookie_path == "/" {
+        return request_path.starts_with('/');
+    }
+    if !request_path.starts_with(cookie_path) {
+        return false;
+    }
+    if cookie_path.ends_with('/') {
+        return true;
+    }
+    request_path
+        .as_bytes()
+        .get(cookie_path.len())
+        .is_none_or(|&b| b == b'/')
